class Solution:
    def canMakePaliQueries(self, s, queries):
        res = []
        for a, b, k in queries:
            cnt = {}
            for c in s[a:b + 1]:
                cnt[c] = cnt.get(c, 0) + 1
            odd = sum(1 for v in cnt.values() if v % 2 == 1)
            res.append(odd // 2 <= k)
        return res

