class Solution:
    def canMakePaliQueries(self, s, queries):
        n = len(s)
        pre = [0] * (n + 1)
        for i, c in enumerate(s):
            pre[i + 1] = pre[i] ^ (1 << (ord(c) - 97))
        res = []
        for a, b, k in queries:
            mask = pre[b + 1] ^ pre[a]
            odd = bin(mask).count('1')
            res.append(odd // 2 <= k)
        return res

