var canMakePaliQueries = function(s, queries) {
    const n = s.length;
    const pre = new Int32Array(n + 1);
    for (let i = 0; i < n; i++) {
        pre[i + 1] = pre[i] ^ (1 << (s.charCodeAt(i) - 97));
    }
    const popcount = x => {
        let c = 0;
        while (x) { x &= x - 1; c++; }
        return c;
    };
    return queries.map(([a, b, k]) => {
        const mask = pre[b + 1] ^ pre[a];
        return Math.floor(popcount(mask) / 2) <= k;
    });
};
